#!/usr/bin/env bash

set -euo pipefail

function usage() {
  echo "Usage: $0 --region <region> --stack-name <stack_name> --template-file <template_file> [--profile <aws_profile>]"
  exit 1
}

PROFILE=""
REGION=""
STACK_NAME=""
TEMPLATE_FILE=""

while [[ $# -gt 0 ]]; do
  case "$1" in
    --profile)
      PROFILE="$2"
      shift 2
      ;;
    --region)
      REGION="$2"
      shift 2
      ;;
    --stack-name)
      STACK_NAME="$2"
      shift 2
      ;;
    --template-file)
      TEMPLATE_FILE="$2"
      shift 2
      ;;
